    // Map drawer view names → nav ID suffix (only where they differ)
    const _drawerViewToNavId = { 'marketing_automation': 'marketing-automation' };

    // Returns the set of allowed nav IDs for the current user (mirrors updateNavVisibility logic)
    const _getAllowedNavIds = () => {
        const _l12 = ['calendar', 'prospects', 'referrals', 'pipeline', 'promotions', 'cases', 'reports', 'documents', 'settings', 'fude', 'milestones'];
        const perms = {
            1: ['calendar','prospects','referrals','pipeline','promotions','marketing-automation','marketing-lists','cases','agents','performance','reports','risk','ai-insights','security','admin','protection','documents','import','integrations','settings','fude','milestones','workflows','lead_forms','surveys','contracts','custom_fields','booking_settings'],
            2: ['calendar','prospects','referrals','pipeline','promotions','marketing-automation','marketing-lists','cases','agents','performance','reports','risk','ai-insights','security','admin','protection','documents','import','integrations','settings','fude','milestones','workflows','lead_forms','surveys','contracts','custom_fields','booking_settings'],
            3: ['calendar','prospects','referrals','pipeline','promotions','cases','performance','reports','protection','documents','settings','fude'],
            4: ['calendar','prospects','referrals','pipeline','promotions','cases','performance','reports','protection','documents','settings','fude'],
            5: _l12, 6: _l12, 7: _l12, 8: _l12, 9: _l12, 10: _l12,
            11: ['calendar','prospects','referrals','promotions','cases','settings','fude','milestones'],
            12: ['calendar','prospects','referrals','fude','milestones'],
            13: ['calendar','prospects','fude','milestones'],
            14: ['calendar','prospects','fude','milestones'],
        };
        let level = 12;
        const user = _currentUser;
        if (user?.role) {
            const m = user.role.match(/Level\s+(\d+)/i);
            if (m) { level = parseInt(m[1]); }
            else {
                const r = user.role.toLowerCase();
                if (r === 'super_admin' || r === 'admin') level = 1;
                else if (r === 'marketing_manager') level = 2;
                else if (r === 'manager') level = 4;
                else if (r === 'team_leader') level = 5;
                else if (r === 'consultant') level = 7;
                else if (r === 'agent') level = 10;
                else if (r === 'customer') level = 13;
                else if (r === 'referrer') level = 14;
            }
        }
        return new Set(perms[level] || perms[12]);
    };

    const renderMobileDrawer = () => {
        const body = document.getElementById('mobile-drawer-body');
        if (!body) return;

        const allowedIds = _getAllowedNavIds();

        let html = '';
        DRAWER_SECTIONS.forEach(section => {
            // Only include items the current user is allowed to see
            const visibleItems = section.items.filter(item => {
                const navId = _drawerViewToNavId[item.view] || item.view;
                return allowedIds.has(navId);
            });
            if (visibleItems.length === 0) return;

            html += `<div class="mobile-drawer-section-title">${section.title}</div>`;
            visibleItems.forEach(item => {
                const isActive = _currentView === item.view ? ' active' : '';
                html += `
                    <button class="mobile-drawer-item${isActive}" onclick="app.navigateTo('${item.view}'); app.closeMobileDrawer()">
                        <i class="${item.icon}"></i>
                        <span>${item.label}</span>
                    </button>
                `;
            });
            html += `<div class="mobile-drawer-divider"></div>`;
        });

        body.innerHTML = html;

        // Sync footer user info
        const avatar = document.getElementById('drawer-user-avatar');
        const nameEl = document.getElementById('drawer-user-name');
        const roleEl = document.getElementById('drawer-user-role');
        if (_currentUser) {
            if (avatar) avatar.src = _currentUser.avatar_url || `https://ui-avatars.com/api/?name=${encodeURIComponent(_currentUser.full_name || 'U')}&background=8B0000&color=fff`;
            if (nameEl) nameEl.textContent = _currentUser.full_name || 'User';
            if (roleEl) roleEl.textContent = _currentUser.role || '—';
        }
    };

    const openMobileDrawer = () => {
        renderMobileDrawer();
        document.getElementById('mobile-drawer')?.classList.add('open');
        document.getElementById('mobile-drawer-overlay')?.classList.add('open');
        document.body.style.overflow = 'hidden';
    };

    const closeMobileDrawer = () => {
        document.getElementById('mobile-drawer')?.classList.remove('open');
        document.getElementById('mobile-drawer-overlay')?.classList.remove('open');
        document.body.style.overflow = '';
    };

    const toggleMobileNav = () => {
        const drawer = document.getElementById('mobile-drawer');
        if (drawer?.classList.contains('open')) {
            closeMobileDrawer();
        } else {
            openMobileDrawer();
        }
    };

    // ── Bottom Nav ───────────────────────────────────────────
    const renderMobileBottomNav = async () => {
        if (document.querySelector('.mobile-bottom-nav')) return;
        const bottomNav = document.createElement('div');
        bottomNav.className = 'mobile-bottom-nav';
        bottomNav.id = 'mobile-bottom-nav';
        bottomNav.innerHTML = `
            <button class="mobile-nav-item" id="bnav-calendar" onclick="app.navigateTo('calendar')">
                <i class="fas fa-calendar-alt"></i>
                <span>Calendar</span>
            </button>
            <button class="mobile-nav-item" id="bnav-prospects" onclick="app.navigateTo('prospects')">
                <i class="fas fa-users"></i>
                <span>Prospects</span>
            </button>
            <button class="mobile-nav-item" id="bnav-pipeline" onclick="app.navigateTo('pipeline')">
                <i class="fas fa-filter"></i>
                <span>Pipeline</span>
            </button>
            <button class="mobile-nav-item" id="bnav-menu" onclick="app.openMobileDrawer()">
                <i class="fas fa-th-large"></i>
                <span>Menu</span>
            </button>
        `;
        document.body.appendChild(bottomNav);
    };

    const updateBottomNavActive = (viewId) => {
        const map = { calendar: 'bnav-calendar', prospects: 'bnav-prospects', pipeline: 'bnav-pipeline' };
        document.querySelectorAll('.mobile-nav-item').forEach(el => el.classList.remove('active'));
        const activeId = map[viewId];
        if (activeId) document.getElementById(activeId)?.classList.add('active');
    };

    // Legacy — kept for any callers
    const showMobileMenu = () => openMobileDrawer();

    // ── Table data-label injection ───────────────────────────
    // Run after every table render so mobile cards show column labels
    const applyMobileTableLabels = () => {
        if (!isMobile()) return;
        document.querySelectorAll('table').forEach(table => {
            const headers = [...table.querySelectorAll('thead th')].map(th => th.textContent.trim());
            if (!headers.length) return;
            table.querySelectorAll('tbody tr').forEach(tr => {
                [...tr.querySelectorAll('td')].forEach((td, i) => {
                    if (headers[i] && !td.hasAttribute('data-label')) {
                        td.setAttribute('data-label', headers[i]);
                    }
                });
            });
        });
    };

    // ── Swipe gestures ───────────────────────────────────────
    const initSwipeActions = () => {
        let startX = 0;
        document.addEventListener('touchstart', (e) => { startX = e.touches[0].clientX; }, { passive: true });
        document.addEventListener('touchend', (e) => {
            const diff = e.changedTouches[0].clientX - startX;
            // Swipe right from left edge → open drawer
            if (diff > 60 && startX < 30 && isMobile()) {
                openMobileDrawer();
            }
            // Swipe left → close drawer if open
            if (diff < -60 && isMobile()) {
                closeMobileDrawer();
            }
        }, { passive: true });
    };

    // ── Pull-to-refresh (fixed) ──────────────────────────────
    const initPullToRefresh = async () => {
        const content = document.querySelector('.content-viewport');
        if (!content) return;

        let startY = 0;
        const refreshEl = document.createElement('div');
        refreshEl.className = 'pull-to-refresh';
        refreshEl.innerHTML = '<i class="fas fa-arrow-down"></i> Pull to refresh';
        content.parentNode.insertBefore(refreshEl, content);

        content.addEventListener('touchstart', (e) => {
            if (content.scrollTop === 0) startY = e.touches[0].clientY;
        }, { passive: true });

        content.addEventListener('touchmove', (e) => {
            if (!startY) return;
            const diff = e.touches[0].clientY - startY;
            if (diff > 0) {
                refreshEl.classList.add('show');
                if (diff > 80) refreshEl.innerHTML = '<i class="fas fa-arrow-up"></i> Release to refresh';
            }
        }, { passive: true });

        content.addEventListener('touchend', async (e) => {
            if (!startY) return;
            const diff = e.changedTouches[0].clientY - startY;
            if (diff > 80) {
                refreshEl.innerHTML = '<i class="fas fa-sync-alt fa-spin"></i> Refreshing...';
                await new Promise(resolve => setTimeout(resolve, 800));
                await navigateTo(_currentView || 'calendar');
                refreshEl.classList.remove('show');
                refreshEl.innerHTML = '<i class="fas fa-arrow-down"></i> Pull to refresh';
            } else {
                refreshEl.classList.remove('show');
                refreshEl.innerHTML = '<i class="fas fa-arrow-down"></i> Pull to refresh';
            }
            startY = 0;
        }, { passive: true });
    };

    // ==================== PHASE 14: OFFLINE SUPPORT ====================

    const initOfflineSupport = () => {
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);

        // Load saved queue
        try {
            const saved = localStorage.getItem('offline_queue');
            if (saved) _offlineQueue = JSON.parse(saved);
        } catch (e) { _offlineQueue = []; }

        updateOfflineIndicator();
    };

    const handleOnline = async () => {
        _isOnline = true;
        UI.toast.success('Back online – syncing data...');
        await processOfflineQueue();
        updateOfflineIndicator();
    };

    const handleOffline = () => {
        _isOnline = false;
        UI.toast.warning('You are offline – changes will be queued');
        updateOfflineIndicator();
    };

    const updateOfflineIndicator = () => {
        let indicator = document.getElementById('offline-indicator');
        if (!indicator) {
            indicator = document.createElement('div');
            indicator.id = 'offline-indicator';
            document.body.appendChild(indicator);
        }

        if (!_isOnline) {
            indicator.innerHTML = `<i class="fas fa-wifi" style="text-decoration:line-through;"></i> Offline(${_offlineQueue.length} pending)`;
            indicator.style.display = 'flex';
        } else if (_offlineQueue.length > 0) {
            indicator.innerHTML = `<i class="fas fa-sync-alt fa-spin"></i> Syncing(${_offlineQueue.length} pending)`;
            indicator.style.display = 'flex';
        } else {
            indicator.style.display = 'none';
        }
    };

    const addToOfflineQueue = (action, data) => {
        const item = { id: Date.now() + Math.random(), action, data, timestamp: new Date().toISOString() };
        _offlineQueue.push(item);
        localStorage.setItem('offline_queue', JSON.stringify(_offlineQueue));
        updateOfflineIndicator();
        UI.toast.info('Action saved offline – will sync when online');
    };

    const processOfflineQueue = async () => {
        if (_offlineQueue.length === 0) return;
        const queue = [..._offlineQueue];
        _offlineQueue = [];
        localStorage.setItem('offline_queue', JSON.stringify(_offlineQueue));
        updateOfflineIndicator();

        let success = 0;
        let fail = 0;
        for (const item of queue) {
            try {
                if (item.action.startsWith('create_')) {
                    await AppDataStore.create(item.action.replace('create_', ''), item.data);
                } else if (item.action.startsWith('update_')) {
                    await AppDataStore.update(item.action.replace('update_', ''), item.data.id, item.data);
                }
                success++;
            } catch (e) {
                fail++;
                _offlineQueue.push(item);
            }
        }
        localStorage.setItem('offline_queue', JSON.stringify(_offlineQueue));
        updateOfflineIndicator();

        if (fail === 0) UI.toast.success(`Synced ${success} offline actions`);
        else UI.toast.warning(`Synced ${success}, failed ${fail} `);
    };

    const offlineCreate = async (tableName, data) => {
        if (_isOnline) return await AppDataStore.create(tableName, data);
        addToOfflineQueue('create_' + tableName, data);
        return { ...data, id: 'offline-' + Date.now(), offline: true };
    };

    const offlineUpdate = async (tableName, id, data) => {
        if (_isOnline) return await AppDataStore.update(tableName, id, data);
        addToOfflineQueue('update_' + tableName, { ...data, id });
        return { ...data, id, offline: true };
    };

    // ========== GOOGLE CALENDAR INTEGRATION FUNCTIONS ==========

    class GoogleCalendarService {
        constructor() {
            this.baseUrl = 'https://www.googleapis.com/calendar/v3';
        }

        async getAccessToken() {
            return await refreshGoogleToken();
        }

        async createEvent(activity) {
            const token = await this.getAccessToken();
            if (!token) return null;

            const event = {
                summary: activity.activity_title || `${activity.activity_type} Meeting`,
                description: activity.discussion_summary || '',
                start: {
                    dateTime: `${activity.activity_date}T${activity.start_time}:00`,
                    timeZone: 'Asia/Kuala_Lumpur'
                },
                end: {
                    dateTime: `${activity.activity_date}T${activity.end_time}:00`,
                    timeZone: 'Asia/Kuala_Lumpur'
                },
                attendees: activity.co_agents ? activity.co_agents.map(a => ({ email: a.email })) : [],
                reminders: {
                    useDefault: true
                },
                extendedProperties: {
                    private: {
                        crm_activity_id: activity.id.toString(),
                        crm_type: activity.activity_type
                    }
                }
            };

            try {
                const response = await fetch(`${this.baseUrl}/calendars/primary/events`, {
                    method: 'POST',
                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
                    body: JSON.stringify(event)
                });
                if (!response.ok) throw new Error('Calendar API error: ' + response.status);
                const data = await response.json();
                return data.id;
            } catch (error) {
                console.error('Error creating Google Calendar event:', error);
                return null;
            }
        }

        async updateEvent(activity, googleEventId) {
            const token = await this.getAccessToken();
            if (!token) return false;

            try {
                const response = await fetch(`${this.baseUrl}/calendars/primary/events/${googleEventId}`, {
                    method: 'PUT',
                    headers: { 'Authorization': `Bearer ${token}`, 'Content-Type': 'application/json' },
                    body: JSON.stringify({
                        summary: activity.activity_title || `${activity.activity_type} Meeting`,
                        description: activity.discussion_summary || '',
                        start: { dateTime: `${activity.activity_date}T${activity.start_time}:00`, timeZone: 'Asia/Kuala_Lumpur' },
                        end: { dateTime: `${activity.activity_date}T${activity.end_time}:00`, timeZone: 'Asia/Kuala_Lumpur' }
                    })
                });
                return response.ok;
            } catch (error) {
                console.error('Error updating Google Calendar event:', error);
                return false;
            }
        }

        async deleteEvent(googleEventId) {
            const token = await this.getAccessToken();
            if (!token) return false;

            try {
                const response = await fetch(`${this.baseUrl}/calendars/primary/events/${googleEventId}`, {
                    method: 'DELETE',
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                return response.ok || response.status === 204;
            } catch (error) {
                console.error('Error deleting Google Calendar event:', error);
                return false;
            }
        }

        async listEvents(timeMin, timeMax) {
            const token = await this.getAccessToken();
            if (!token) return [];

            try {
                const params = new URLSearchParams({
                    timeMin: timeMin.toISOString(), timeMax: timeMax.toISOString(),
                    singleEvents: 'true', orderBy: 'startTime'
                });
                const response = await fetch(`${this.baseUrl}/calendars/primary/events?${params}`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                if (!response.ok) throw new Error('Calendar API error: ' + response.status);
                const data = await response.json();
                return data.items || [];
            } catch (error) {
                console.error('Error listing Google Calendar events:', error);
                return [];
            }
        }
    }

    class SyncManager {
        constructor() {
            this.googleCalendar = new GoogleCalendarService();
            this.syncInProgress = false;
            this.lastSyncTime = null; // updated in-memory after each sync
        }

        async syncCRMtoGoogle() {
            if (this.syncInProgress) return;
            this.syncInProgress = true;

            try {
                const activities = await AppDataStore.getAll('activities');
                const syncLog = this.getSyncLog();

                let synced = 0, created = 0, updated = 0, deleted = 0;

                for (const activity of activities) {
                    const syncRecord = syncLog.find(s => s.activity_id === activity.id);

                    if (this.needsSync(activity, syncRecord)) {
                        if (activity.status === 'cancelled' && syncRecord?.google_event_id) {
                            await this.googleCalendar.deleteEvent(syncRecord.google_event_id);
                            this.removeSyncRecord(activity.id);
                            deleted++;
                        } else if (syncRecord?.google_event_id) {
                            await this.googleCalendar.updateEvent(activity, syncRecord.google_event_id);
                            await this.updateSyncRecord(activity.id, syncRecord.google_event_id);
                            updated++;
                        } else {
                            const googleEventId = await this.googleCalendar.createEvent(activity);
                            if (googleEventId) {
                                await this.addSyncRecord(activity.id, googleEventId);
                                created++;
                            }
                        }
                        synced++;
                    }
                }

                this.lastSyncTime = new Date().toISOString();
                // Persist last sync time to Supabase via integration_connections.last_sync_at
                try {
                    const _syncConn = await getGoogleConnection();
                    if (_syncConn) {
                        AppDataStore.update('integration_connections', _syncConn.id, { last_sync_at: this.lastSyncTime }).catch(() => {});
                    }
                } catch (_) {}

                if (created || updated || deleted) {
                    // Only show toast if something actually synced to avoid spam
                    UI.toast.success(`Google Calendar sync complete: ${created} created`);
                }
            } catch (error) {
                console.error('Sync error:', error);
            } finally {
                this.syncInProgress = false;
            }
        }

        async syncGoogleToCRM() {
            if (this.syncInProgress) return;
            this.syncInProgress = true;
            try {
                const timeMin = new Date(Date.now() - 30 * 86400000);
                const timeMax = new Date(Date.now() + 30 * 86400000);
                const googleEvents = await this.googleCalendar.listEvents(timeMin, timeMax);
                if (!googleEvents.length) { this.syncInProgress = false; return; }

                const syncLog = await this.getSyncLog();
                let imported = 0;
                for (const gEvent of googleEvents) {
                    // Skip events that originated from CRM
                    if (gEvent.extendedProperties?.private?.crm_activity_id) continue;
                    // Skip already-synced events
                    if (syncLog.find(s => s.google_event_id === gEvent.id)) continue;

                    const startDate = gEvent.start?.date || gEvent.start?.dateTime?.split('T')[0];
                    const startTime = gEvent.start?.dateTime?.split('T')[1]?.substring(0, 5) || '09:00';
                    const endTime = gEvent.end?.dateTime?.split('T')[1]?.substring(0, 5) || '10:00';

                    const activity = await AppDataStore.create('activities', {
                        activity_title: gEvent.summary || 'Google Calendar Event',
                        activity_type: 'Call',
                        activity_date: startDate,
                        start_time: startTime,
                        end_time: endTime,
                        status: 'completed',
                        discussion_summary: gEvent.description || '',
                        lead_agent_id: _currentUser?.id || 1,
                        source: 'google_calendar',
                        google_event_id: gEvent.id,
                        created_at: new Date().toISOString()
                    });

                    // Record import in sync_history (was localStorage-only before)
                    await this.addSyncRecord(activity?.id, gEvent.id, 'google_to_crm');
                    imported++;
                }
                if (imported > 0) UI.toast.success(`Imported ${imported} events from Google Calendar`);
            } catch (error) {
                console.error('Import error:', error);
            } finally {
                this.syncInProgress = false;
            }
        }

        needsSync(activity, syncRecord) {
            if (!syncRecord) return true;
            const activityUpdated = new Date(activity.updated_at || activity.created_at);
            const syncUpdated = new Date(syncRecord.last_synced_at);
            return activityUpdated > syncUpdated;
        }

        async getSyncLog() {
            try {
                const records = await AppDataStore.getAll('sync_history');
                return (records || []).map(r => ({
                    activity_id: r.activity_id,
                    google_event_id: r.google_event_id,
                    last_synced_at: r.synced_at || r.last_synced_at
                }));
            } catch (_) { return []; }
        }

        async addSyncRecord(activityId, googleEventId, direction = 'crm_to_google') {
            try {
                const connection = await getGoogleConnection();
                if (connection && _currentUser) {
                    await AppDataStore.create('sync_history', {
                        integration_id: connection.integration_id,
                        user_id: _currentUser.id,
                        activity_id: activityId,
                        google_event_id: googleEventId,
                        direction,
                        status: 'success',
                        error_message: '',
                        synced_at: new Date().toISOString()
                    });
                }
            } catch (_) {}
        }

        async updateSyncRecord(activityId, googleEventId) {
            // sync_history rows are append-only; the latest row wins for the same activity_id.
            await this.addSyncRecord(activityId, googleEventId, 'crm_to_google');
        }

        async removeSyncRecord(activityId) {
            try {
                const records = await AppDataStore.query('sync_history', { activity_id: activityId });
                for (const r of records || []) {
                    await AppDataStore.delete('sync_history', r.id);
                }
            } catch (_) {}
        }

        resolveConflict(choice, activityId, eventId) {
            UI.hideModal();
            UI.toast.success(`Conflict resolved. Chose: ${choice}`);
        }
    }

    // Refresh Google Token - mock implementation for demo
